 {"id":"bd-3bxhj.4.6","title":"task(opentui-import translation): Translate side effects and async workflows into Cmd/subscription orchestration","description":"Objective: Generate robust async orchestration code for effects/timers/IO using Cmd and subscriptions with deterministic lifecycle management.\\n\\nAcceptance criteria:\\n1. Effect cancellation/timeout semantics are explicit and testable.\\n2. Retries/backoff translate without hidden nondeterminism.\\n3. Error propagation aligns with contract and certification logging requirements.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:32:18.100890523Z","created_by":"ubuntu","updated_at":"2026-02-24T21:37:32.379137544Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["effects","opentui-import","translation"],"dependencies":[{"issue_id":"bd-3bxhj.4.6","depends_on_id":"bd-3bxhj.3.5","type":"blocks","created_at":"2026-02-24T21:37:32.379074095Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.6","depends_on_id":"bd-3bxhj.4","type":"parent-child","created_at":"2026-02-24T21:32:18.100890523Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.6","depends_on_id":"bd-3bxhj.4.2","type":"blocks","created_at":"2026-02-24T21:37:31.906564246Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
